define('block_blumod/assign_competencies',[],function(){const MIN_FILTER_CHARS=3;function init(){const e=document.getElementById('bluselector'),t=document.getElementById('competencies');if(!e||!t)return;e.value&&(asignarBLU(e.value),llamarCompetencies(e.value)),e.addEventListener('change',function(t){asignarBLU(t.target.value),llamarCompetencies(t.target.value)}),document.querySelectorAll('.validate-selected').forEach(function(t){t.addEventListener('click',function(t){e.value||t.preventDefault()})}),t.addEventListener('click',function(t){const n=t.target.closest('button[data-action][data-from]');n&&executeAction(n.dataset.action,n.dataset.from,e)})}function executeAction(e,t,n){if(!e||!t||!n.value)return;const o=document.getElementById(t);if(!o||!o.value||isFrameworkOption(o.value))return;const r=n.value;asignarBLU(r),llamarCompetencies(r,e,o.value)}function asignarBLU(e){document.querySelectorAll('[name=id], [name=bluid]').forEach(function(t){t.value=e})}function llamarCompetencies(e,t,n){const o=(new URLSearchParams(window.location.search)).get('courseid');if(!o)return;const r=new URLSearchParams({courseid:o,bluid:e});t&&n&&(r.set('action',t),r.set('modid',n));const i=M.cfg.wwwroot+'/blocks/blumod/competencies.php?'+r.toString();fetch(i).then(function(e){return e.text()}).then(function(e){const t=document.getElementById('competencies');t&&(t.innerHTML=e,bindSearchFilter())}).catch(function(){console.log('Error fetching competencies')})}function bindSearchFilter(){const e=document.getElementById('competencyselector_search'),t=document.getElementById('competencyselector_available');e&&t&&(applySearchFilter(e,t),e.addEventListener('input',function(){applySearchFilter(e,t)}))}function applySearchFilter(e,t){const n=e.value.trim().toLowerCase(),o=n.length>=MIN_FILTER_CHARS;Array.prototype.forEach.call(t.options,function(e){isFrameworkOption(e.value)?e.hidden=!1:o?e.hidden=e.text.toLowerCase().indexOf(n)===-1:e.hidden=!1})}function isFrameworkOption(e){return'string'==typeof e&&0===e.indexOf('F')}return{init:init}});